// mood → vibes (weighted — first = most likely)
const MOOD_MAP = {
  nostalgic:  ['bittersweet','missing','happy'],
  tender:     ['bittersweet','chill','missing'],
  electric:   ['rave','happy','bittersweet'],
  golden:     ['happy','bittersweet','chill'],
  aching:     ['missing','sad','bittersweet'],
  unraveling: ['sad','missing','chill'],
  restless:   ['rave','happy','sad'],
  quiet:      ['chill','bittersweet','sad'],
};

const MOOD_HINTS = {
  nostalgic:   "Something that aches like a memory.",
  tender:      "A song that holds you.",
  electric:    "Something that matches the buzz.",
  golden:      "A moment worth staying in.",
  aching:      "For the weight you're still carrying.",
  unraveling:  "When coming apart feels almost right.",
  restless:    "Something to move through.",
  quiet:       "Nothing that asks too much of you.",
};

// accent colors per mood
const MOOD_ACC = {
  nostalgic:'#ff3c00', tender:'#ff00aa', electric:'#00e5ff',
  golden:'#b4ff00',   aching:'#ff3c00',  unraveling:'#aa00ff',
  restless:'#ff6600', quiet:'#00ffaa',
};
const MOOD_ACC2 = {
  nostalgic:'#ff6640', tender:'#ff44cc', electric:'#33eeff',
  golden:'#ccff44',   aching:'#ff5522',  unraveling:'#cc44ff',
  restless:'#ff8833', quiet:'#33ffbb',
};

// ── STATE ─────────────────────────────────────────────────
let curMood='electric', curSong=null, playing=false, playedCount=0;
const $=id=>document.getElementById(id);

// ── MARQUEE ───────────────────────────────────────────────
(()=>{
  const all=Object.values(VIBES).flat().filter((s,i,a)=>a.findIndex(x=>x.title===s.title)===i);
  const t=all.map(s=>`<span>${s.title}</span><span class="dot">·</span>`).join('');
  $('mtrack').innerHTML=t+t;
})();

// ── INIT ──────────────────────────────────────────────────
window.addEventListener('DOMContentLoaded',()=>{
  $('landPhoto').style.backgroundImage=`url('${IMGS.cover}')`;
});

// ── TRANSITIONS ───────────────────────────────────────────
function fx(fn){const ov=$('overlay');ov.classList.add('on');setTimeout(()=>{fn();ov.classList.remove('on')},520);}
function hide(id){$(id).style.display='none'}
function show(id,d='block'){$(id).style.display=d}

function goLanding(){fx(()=>{hide('moods');show('landing','flex')})}
function goMoods(){fx(()=>{hide('landing');hide('player');hide('closing');show('moods','flex')})}
function restart(){playing=false;playedCount=0;curSong=null;fx(()=>{hide('closing');show('landing','flex')})}

// ── SONG PICKER ───────────────────────────────────────────
function pickFromMood(mood, exclude){
  const weights=MOOD_MAP[mood]||['happy'];
  let pool=[];
  weights.forEach((vibe,wi)=>{
    (VIBES[vibe]||[]).forEach(s=>{
      if(!exclude||s.title!==exclude.title){
        const w=Math.max(1,3-wi);
        for(let i=0;i<w;i++) pool.push({...s,vibe});
      }
    });
  });
  if(!pool.length){
    const all=Object.values(VIBES).flat();
    return all[Math.floor(Math.random()*all.length)];
  }
  return pool[Math.floor(Math.random()*pool.length)];
}

function pickMood(mood, acc, acc2){
  curMood=mood; playedCount=0;
  curSong=pickFromMood(mood,null);
  // update CSS vars
  document.documentElement.style.setProperty('--acc', acc||MOOD_ACC[mood]||'#ff3c00');
  document.documentElement.style.setProperty('--acc2', acc2||MOOD_ACC2[mood]||'#ff6640');
  fx(()=>{hide('moods');show('player');render();});
}

function skipSong(){
  curSong=pickFromMood(curMood,curSong);
  playedCount++;
  fx(render);
}
function nextSong(){
  curSong=pickFromMood(curMood,curSong);
  playedCount++;
  if(playedCount>9){fx(()=>{hide('player');show('closing','flex')})}
  else fx(render);
}

// ── VINYL DRAW ────────────────────────────────────────────
function drawVinyl(photoKey, hue){
  const cv=$('vCanvas'),sz=480,ctx=cv.getContext('2d'),cx=sz/2,cy=sz/2,R=sz/2-1;
  const src=IMGS[photoKey]||IMGS.fall;
  const img=new Image();
  img.onload=()=>{
    ctx.save();
    ctx.beginPath();ctx.arc(cx,cy,R,0,Math.PI*2);ctx.clip();

    const sc=Math.max(sz/img.width,sz/img.height);
    ctx.drawImage(img,(sz-img.width*sc)/2,(sz-img.height*sc)/2,img.width*sc,img.height*sc);

    // tint
    ctx.globalAlpha=0.32;ctx.fillStyle=hue;
    ctx.beginPath();ctx.arc(cx,cy,R,0,Math.PI*2);ctx.fill();
    ctx.globalAlpha=1;

    // grooves
    for(let i=0;i<42;i++){
      const ri=R*.18+i*(R*.82/42);
      ctx.beginPath();ctx.arc(cx,cy,ri,0,Math.PI*2);
      ctx.strokeStyle=`rgba(0,0,0,${.028+i*.0018})`;ctx.lineWidth=0.65;ctx.stroke();
    }

    // spin streaks
    for(let i=0;i<230;i++){
      const a=(i/230)*Math.PI*2;
      const g=ctx.createLinearGradient(cx+Math.cos(a)*R*.1,cy+Math.sin(a)*R*.1,cx+Math.cos(a)*R,cy+Math.sin(a)*R);
      g.addColorStop(0,'rgba(0,0,0,0)');g.addColorStop(.55,'rgba(0,0,0,0)');g.addColorStop(1,'rgba(0,0,0,0.16)');
      ctx.strokeStyle=g;ctx.lineWidth=1.2;ctx.globalAlpha=0.14;
      ctx.beginPath();ctx.moveTo(cx+Math.cos(a)*R*.1,cy+Math.sin(a)*R*.1);ctx.lineTo(cx+Math.cos(a)*R,cy+Math.sin(a)*R);ctx.stroke();
    }
    ctx.globalAlpha=1;

    // edge vignette
    const ev=ctx.createRadialGradient(cx,cy,R*.45,cx,cy,R);
    ev.addColorStop(0,'rgba(0,0,0,0)');ev.addColorStop(1,'rgba(0,0,0,0.62)');
    ctx.fillStyle=ev;ctx.beginPath();ctx.arc(cx,cy,R,0,Math.PI*2);ctx.fill();

    // center dark
    const cd=ctx.createRadialGradient(cx,cy,0,cx,cy,R*.2);
    cd.addColorStop(0,'rgba(0,0,0,0.75)');cd.addColorStop(1,'rgba(0,0,0,0)');
    ctx.fillStyle=cd;ctx.beginPath();ctx.arc(cx,cy,R*.2,0,Math.PI*2);ctx.fill();

    ctx.restore();
  };
  img.src=src;
}

// ── RENDER ────────────────────────────────────────────────
function render(){
  if(!curSong) curSong=pickFromMood(curMood,null);
  const s=curSong, n=playedCount+1;
  const acc=MOOD_ACC[curMood]||'#ff3c00';
  const acc2=MOOD_ACC2[curMood]||'#ff6640';

  $('pSeason').textContent=`${(s.vibe||'').toUpperCase()} — SIDE A`;
  $('pNum').textContent=String(n).padStart(2,'0');
  $('pTitle').textContent=s.title;
  $('pArtist').textContent=s.artist;
  $('pMoodPill').textContent=curMood;
  $('pHint').textContent=MOOD_HINTS[curMood]||'';
  $('pCount').textContent=`${n} / ∞`;
  // YouTube link
  const ytEl=$('ytBtn');
  if(s.yt){ytEl.href=s.yt;ytEl.style.display='inline-flex';}
  else ytEl.style.display='none';

  const short=s.title.split(' ').slice(0,3).join(' ');
  $('vlTitle').innerHTML=short+'<br>'+s.artist.toUpperCase().split(' ').slice(0,2).join(' ');
  $('vlNum').textContent='A'+n;

  // accent colors
  document.documentElement.style.setProperty('--acc',acc);
  document.documentElement.style.setProperty('--acc2',acc2);
  $('pColorbar').style.background=acc;
  $('playRing').style.background=acc;

  // right panel
  const ph=s.photo||'fall';
  $('pRightPhoto').style.backgroundImage=`url('${IMGS[ph]||IMGS.fall}')`;
  $('pRightTint').style.background=`radial-gradient(ellipse 80% 80% at 50% 50%, ${acc2}22 0%, transparent 70%)`;

  drawVinyl(ph, s.hue);

  playing=false;
  $('waveform').classList.add('paused');
  $('vDisc').classList.remove('playing');
  $('needle').classList.remove('on');
  $('playIco').innerHTML='<polygon points="2,1 12,6.5 2,12"/>';
}

function togglePlay(){
  playing=!playing;
  $('vDisc').classList.toggle('playing',playing);
  $('needle').classList.toggle('on',playing);
  $('waveform').classList.toggle('paused',!playing);
  $('playIco').innerHTML=playing
    ?'<rect x="1" y="1" width="4" height="11"/><rect x="7" y="1" width="4" height="11"/>'
    :'<polygon points="2,1 12,6.5 2,12"/>';
  // open YouTube on first play press
  if(playing && curSong && curSong.yt){
    window.open(curSong.yt,'_blank','noopener');
  }
}

curSong=pickFromMood('electric',null);
render();